/**
 * Cellar ŌĆö nbdev-style selective export to a `.py` module.
 *
 * A notebook can name a target `.py` module (`notebook.metadata.cellar.export_target`,
 * nbdev's `#|default_exp`) and mark individual code cells for export
 * (`metadata.cellar.export`, nbdev's `#|export`). This module reads the marked
 * cells IN ORDER and writes a clean Python module: a "do not edit" header, a
 * best-effort `__all__`, and the exported sources concatenated.
 *
 * This is deliberately DISTINCT from the jupytext `.py` export in
 * `jupytext-actions.ts`: that mirrors the WHOLE notebook as a text notebook (cell
 * markers, every cell). This writes a lean module of only the marked cells ŌĆö the
 * nbdev "library from notebook" model, where the generated module is committed to
 * git (so it is NOT gitignored).
 *
 * Output is deterministic and idempotent: identical marked content yields a
 * byte-identical file, so re-exporting produces no git diff.
 */

import { writeFileSync, readFileSync, existsSync, mkdirSync } from 'node:fs';
import { dirname, basename } from 'node:path';
import { resolveInWorkspace } from './fstree';
import { logicalLines } from './imports';
import { isExportCell } from '../exportRole';
import type { Cell, NotebookDoc } from './types';

/** The header stamped at the top of every generated module. */
const HEADER = '# AUTOGENERATED BY CELLAR! DO NOT EDIT!';

export interface ExportResult {
	/** true if the file was (re)written; false if unchanged / nothing to do. */
	written: boolean;
	/** workspace-relative target path, or null when no target is configured. */
	target: string | null;
	/** number of cells exported. */
	count: number;
	/** why nothing was written, when `written` is false. */
	reason?: 'no-target' | 'no-cells' | 'unchanged';
}

/**
 * Best-effort top-level names for `__all__`, from a single cell's source:
 * top-level `def`/`class` and simple top-level assignments (`X = ŌĆ”`,
 * `X: T = ŌĆ”`, `A, B = ŌĆ”`). Names starting with `_` are omitted (nbdev/Python
 * convention: private). Order is preserved; the caller dedupes across cells.
 *
 * Uses the imports tokenizer's `logicalLines` so `=`/`def`/`class` inside a
 * string or a nested (indented) scope are never mistaken for a definition.
 * Known limits (documented, acceptable for a best-effort `__all__`): augmented
 * assignments (`X += ŌĆ”`), `del`, and dynamically-created names are invisible.
 */
export function topLevelNames(source: string): string[] {
	const names: string[] = [];
	for (const line of logicalLines(source)) {
		if (line.indent !== 0) continue; // only module-level statements define exports
		const head = line.raw.replace(/^\s+/, '');
		// def / class (including `async def`)
		const dc = head.match(/^(?:async\s+)?(?:def|class)\s+([A-Za-z_]\w*)/);
		if (dc) {
			names.push(dc[1]);
			continue;
		}
		// annotated single assignment: `NAME: T = ŌĆ”`
		const ann = head.match(/^([A-Za-z_]\w*)\s*:\s*[^=]+=(?!=)/);
		if (ann) {
			names.push(ann[1]);
			continue;
		}
		// plain assignment (single or tuple): LHS before the first real `=`.
		const eq = head.match(/^([^=]+?)=(?!=)/);
		if (eq) {
			const lhs = eq[1].trim();
			// Only accept an LHS that is purely comma-separated identifiers, so
			// `a == b`, `a[i] = ŌĆ”`, `a.b = ŌĆ”`, `x <= y` never leak in.
			if (/^[A-Za-z_]\w*(\s*,\s*[A-Za-z_]\w*)*$/.test(lhs)) {
				for (const n of lhs.split(',')) names.push(n.trim());
			}
		}
	}
	// Drop private names, dedupe, preserve first-seen order.
	const seen = new Set<string>();
	const out: string[] = [];
	for (const n of names) {
		if (n.startsWith('_') || seen.has(n)) continue;
		seen.add(n);
		out.push(n);
	}
	return out;
}

/** Render a Python list literal for `__all__` (deterministic, single-quoted). */
function renderAll(names: string[]): string {
	if (!names.length) return '__all__ = []';
	return `__all__ = [${names.map((n) => `'${n}'`).join(', ')}]`;
}

/**
 * Build the full module text from the exported cells (already filtered + in
 * document order). Deterministic: a trailing newline, single blank line between
 * blocks, no incidental whitespace, so re-exporting identical content is a
 * byte-for-byte no-op.
 */
export function generateModule(exportedSources: string[], sourceName: string): string {
	const allNames: string[] = [];
	const seen = new Set<string>();
	for (const src of exportedSources) {
		for (const n of topLevelNames(src)) {
			if (!seen.has(n)) {
				seen.add(n);
				allNames.push(n);
			}
		}
	}
	const blocks: string[] = [`${HEADER}\n# Source notebook: ${sourceName}`, renderAll(allNames)];
	for (const src of exportedSources) {
		const trimmed = src.replace(/\s+$/, ''); // drop trailing blank lines within a cell
		if (trimmed) blocks.push(trimmed);
	}
	return blocks.join('\n\n') + '\n';
}

/**
 * The configured export target for a doc: the notebook-level `export_target`
 * (workspace-relative `.py` path), or a `#|default_exp <module>` directive found
 * in any cell (nbdev familiarity; the UI field is the primary mechanism). Returns
 * null when neither is present.
 */
export function resolveTarget(doc: NotebookDoc): string | null {
	const explicit = doc.metadata?.cellar?.export_target;
	if (typeof explicit === 'string' && explicit.trim()) return explicit.trim();
	for (const c of doc.cells) {
		if (c.cell_type !== 'code') continue;
		const m = c.source.match(/^\s*#\s*\|\s*default_exp\s+([^\s#]+)/m);
		if (m) {
			// nbdev writes a dotted module path (`pkg.utils`); map it to a file path.
			const mod = m[1].trim();
			return mod.endsWith('.py') ? mod : mod.replace(/\./g, '/') + '.py';
		}
	}
	return null;
}

/**
 * Generate the `.py` module for a notebook document. Writes only when a target is
 * configured AND at least one code cell is marked for export AND the generated
 * text differs from what is already on disk (so an unchanged re-export touches
 * nothing ŌĆö no mtime churn, no git diff). The write is path-guarded to the
 * workspace and creates parent directories as needed.
 *
 * Never throws for the "nothing to do" cases (no target / no marked cells): the
 * caller (auto-on-save) must not have a save broken by an absent target. A bad
 * target path (escapes the workspace) still throws ŌĆö that is a real error the
 * manual button surfaces to the user.
 */
export function exportNotebookToPy(doc: NotebookDoc): ExportResult {
	const target = resolveTarget(doc);
	if (!target) return { written: false, target: null, count: 0, reason: 'no-target' };

	const exported = doc.cells.filter((c: Cell) => isExportCell(c)).map((c) => c.source);
	if (!exported.length) return { written: false, target, count: 0, reason: 'no-cells' };

	const abs = resolveInWorkspace(target); // throws on workspace escape
	const sourceName = basename(doc.path);
	const text = generateModule(exported, sourceName);

	// Idempotent: skip the write when the file already holds identical bytes.
	if (existsSync(abs) && safeRead(abs) === text) {
		return { written: false, target, count: exported.length, reason: 'unchanged' };
	}
	mkdirSync(dirname(abs), { recursive: true });
	writeFileSync(abs, text);
	return { written: true, target, count: exported.length };
}

function safeRead(abs: string): string | null {
	try {
		return readFileSync(abs, 'utf8');
	} catch {
		return null;
	}
}
